CustomField.formula:
IF(
   AND( TEXT(Territory2.Owned_By_Company__c) = "LSDX"
        ,OR(CONTAINS(Territory2.Name , "LifeSci")
            ,CONTAINS(Territory2.Name , "LifSci")
           )
      )
   ,"Life Science"
   ,IF(
		AND( TEXT(Territory2.Owned_By_Company__c) = "LSDX"
		     ,OR(CONTAINS(SUBSTITUTE(Territory2.Name, 'LSDX', '')   , "DX")
			 ,CONTAINS(SUBSTITUTE(Territory2.Name, 'LSDX', '') , "Dx")
			)
		   )
        ,"Diagnostic"
        ,""
      )
   )
